import{_ as e,o as b,c as t,j as r,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const _=JSON.parse('{"title":"SAM装甲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/战斗机器人/4.A级/SAM装甲.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/战斗机器人/4.A级/SAM装甲.md"}'),o={name:"4.资源分区/7.物品与装备/7.载具及随从/战斗机器人/4.A级/SAM装甲.md"};function A(d,a,p,S,l,i){return b(),t("div",null,[...a[0]||(a[0]=[r("h1",{id:"sam装甲",tabindex:"-1"},[s("SAM装甲 "),r("a",{class:"header-anchor",href:"#sam装甲","aria-label":'Permalink to "SAM装甲"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),n('<h1 id="sam装甲-1" tabindex="-1">SAM装甲 <a class="header-anchor" href="#sam装甲-1" aria-label="Permalink to &quot;SAM装甲&quot;">​</a></h1><p>SAM装甲</p><p>SAM装甲<br> 描述：格拉默帝国为抵御虫群，创造出了以女皇之血为根基的基因改造人部队格拉默铁骑，而火萤型战略强袭装甲则是格拉默铁骑所着的最常见的量产型人型机甲型号之一，其统一简称为SAM装甲。<br> 火萤Ⅳ型战略强袭装甲<br> A+4000<br> 格拉默铁骑在苍穹战线上投入最多的装甲类型，外形为高大的白色机械装甲，拥有极强的机动性和突击能力，同时强袭装甲对于格拉默铁骑而言并不仅仅只是一件用生命驱使的战斗工具，也是让他们得以存活的医疗舱。<br> 载具本质：科技本质<br> 载具类型：战斗机器人<br> 载具专业：战斗机器人<br> 结构66 装甲36 移动速度100米/轮<br> 处于飞行状态下可进行加速，加速度50米/次，最大移动速度400米/轮。<br> 可搭乘人员：1<br> 体积：7<br> 普通飞行<br> 适应环境：水下 陆地 空中 宇宙<br> 免疫B环境</p><p>火萤变身器<br> SAM装甲采用统一的萤火虫式变身器，在迅捷动作启动后驾驶员会自动进入装甲内部，每一台SAM装甲与驾驶员生理信息绑定，其他人无法进入以及该使用装甲。<br> 茧式源火中枢<br> SAM装甲的动力来源于其体内的女皇之血，借此SAM装甲可以与其驾驶员进行同频以进行战斗，在驾驶员生命状态低迷时，同步率会愈发增高。当驾驶员的生命被L伤填满时，装甲将额外获得等同于耐力上附加成功的装甲防御。<br> 指令-闪燃堆进<br> 依靠时部的火焰推进器,SAM装甲可以极快的速度打出拳击，手部的火焰迸发装置则可以在命中的瞬间给予敌人严重的烧伤。<br> 装甲的手臂视为武器伤害3L，造成灼烧伤害的近战武器。被拳击击中的敌人将被严重的烧伤，这致使其在本回合内医疗点或吸血所能回复的总量减少3L。<br> 指令-天火轰击<br> 短暂蓄力后跃起，借助机甲本身惯性以及腿部的火焰喷射装置带来的力量向敌人踢击，在命中的瞬间使用脚步的火焰发射器，将自身弹开的同时造成二次伤害。<br> 装甲的腿部被视为武器伤害3L，造成灼伤伤害的近战武器。腿部装甲的攻击将产生一个7m范围的圆形冲击波处在范围内的人将承受24L物理伤害，反射豁免</p><p>——<br> 逐级提升：</p><p>觉醒<br> S+8000<br> 「我梦见一片焦土···」<br> 「一株破土而生的新蕊···」<br> 「它迎着朝阳绽放···」<br> 「向我低语呢喃···」<br> 「飞萤扑火···」<br> 「···向死而生」<br> 特异本质<br> 结构112 装甲60 移动速度660米/轮<br> 处于飞行状态下可进行加速，加速度660米/轮，最大移动速度5280米/轮。<br> 可搭乘人员：1<br> 体积：7<br> 完美飞行<br> 适应环境：水下 陆地 空中 宇宙<br> 免疫a环境<br> 火萤Ⅳ型-完全燃烧<br> 「直至一切，焚烧殆尽」<br> SAM装甲在攻击时，驾驶员可以逸择承受任意点数的不可豁免的L伤，若如此做在本次攻击命中时SAM装甲样获得等同于本次承受L伤总数的灼热点数（最多48点），灼热点数上限为96点，当灼热点数充满时，可以通过一个自由动作进入【完全燃烧】状态，在进入【完全然烧】状态时，并使先攻增加耐力属性点，【完全燃烧】状态将持续整场战斗，不可主动退出,进入战斗时自动获得48点灼热点数。<br> 在【完全燃烧】状态下，茧式源火中枢提供的防御更改为等额的全伤害吸收,并将基础移速和加速度提升960m/轮，最大移动速度提升为7680m/轮<br> 火萤Ⅳ型-底火斩击<br> 「为生而战」<br> 在【完全燃烧】状态下,SAM装甲将获得一双幽绿色的火焰长剑，这视为拥有12L【10威猛】，【8加骰】，特性的近战武器,在触发茧式源火中枢效果下的SAM机甲与其驾驶员视为一体，并使双剑获得【吸血3】特性，其吸血获得的恢复不仅可以作用于机甲本身也可以作用于其驾驶员。<br> 火萤Ⅳ型-死星过载<br> 「我将,点燃星海」<br> 在【完全燃烧】状态下，SAM机甲的斩击在命中敌人后将会为敌方添上等同于感知上附加成功的灼烧伤害易伤,持续一个场景，同时【完全燃烧】状态下的斩击还会对敌方造成【超击破-燃烧状态】效果。<br> 【超击破-燃烧状态】<br> 若SAM机甲的任意破防类型效果（如破甲，高速，威猛）将相对应的护甲完全破除时，每溢出的一点破甲将会额外造成1点燃烧点数视为四档异常，获得的燃烧点数不超过当次攻击造成的伤害。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const c=e(o,[["render",A]]);export{_ as __pageData,c as default};
